SELECT COUNT(*) as Total_Episodes
FROM episodes
WHERE end_time <= '2023-01-01 00:00:00' AND episode_status = 'completed';

SELECT AVG(average_reward) AS typical_performance_score
FROM reward_metrics
WHERE agent_id = 1 AND episode_id = 1;

SELECT session_id, session_name
FROM training_sessions
WHERE session_status <> 'active';

SELECT a.agent_name, ap.reward
FROM agents a
INNER JOIN agent_performance ap ON a.agent_id = ap.agent_id;

SELECT MAX(max_reward) 
FROM reward_metrics 
WHERE agent_id = (SELECT agent_id FROM agents WHERE agent_name = 'Agent B');

SELECT agent_id, average_reward, environment_id 
FROM reward_metrics
ORDER BY metric_date DESC;
